// Some portions generated by Codex
package org.eclipse.rdf4j.sail.multirepo.config;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatExceptionOfType;

import java.util.List;

import org.eclipse.rdf4j.model.Model;
import org.eclipse.rdf4j.model.impl.LinkedHashModel;
import org.eclipse.rdf4j.sail.multirepo.config.MultiRepoStoreConfig.MemberConfig;
import org.eclipse.rdf4j.sail.nativerdf.config.NativeStoreFactory;
import org.junit.jupiter.api.Test;

class MultiRepoStoreConfigTest {

	@Test
	void exportAndParseRoundTripPreservesOrderedMembers() {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		config.addRepositoryMember("left");
		config.addLocationMember("native-relative", NativeStoreFactory.SAIL_TYPE);
		config.addRepositoryMember("right");

		Model model = new LinkedHashModel();
		var implNode = config.export(model);

		MultiRepoStoreConfig parsed = new MultiRepoStoreConfig();
		parsed.parse(model, implNode);

		assertThat(parsed.getMembers())
				.extracting(MemberConfig::getRepositoryId, MemberConfig::getRepositoryLocation,
						MemberConfig::getSailType)
				.containsExactly(
						org.assertj.core.groups.Tuple.tuple("left", null, null),
						org.assertj.core.groups.Tuple.tuple(null, "native-relative", NativeStoreFactory.SAIL_TYPE),
						org.assertj.core.groups.Tuple.tuple("right", null, null));
	}

	@Test
	void validateFailsWhenMemberHasNoSource() {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		config.addMember(new MemberConfig(null, null, null));

		assertThatExceptionOfType(org.eclipse.rdf4j.sail.config.SailConfigException.class)
				.isThrownBy(config::validate)
				.withMessageContaining("exactly one of repositoryId or repositoryLocation");
	}

	@Test
	void validateFailsWhenFilesystemMemberHasNoSailType() {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		config.addMember(new MemberConfig(null, "native-relative", null));

		assertThatExceptionOfType(org.eclipse.rdf4j.sail.config.SailConfigException.class)
				.isThrownBy(config::validate)
				.withMessageContaining("must define sailType");
	}

	@Test
	void validateFailsWhenFilesystemMemberHasUnsupportedSailType() {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		config.addMember(new MemberConfig(null, "store", "rdf4j:MemoryStore"));

		assertThatExceptionOfType(org.eclipse.rdf4j.sail.config.SailConfigException.class)
				.isThrownBy(config::validate)
				.withMessageContaining("unsupported sailType");
	}

	@Test
	void getMembersReturnsDefensiveCopy() {
		MultiRepoStoreConfig config = new MultiRepoStoreConfig();
		config.addRepositoryMember("left");

		List<MemberConfig> members = config.getMembers();

		assertThatExceptionOfType(UnsupportedOperationException.class)
				.isThrownBy(() -> members.add(MemberConfig.repository("right")));
	}
}
